var provider = new ethers.providers.JsonRpcProvider("<YOUR URL>")

const gasPrice = 20e9; // 20 gwei (1 gwei = 10^9 wei)
// private key (for test purpose only, you can use your own address and private key to send ETH. Don't share them.)
const wallet = new ethers.Wallet("<YOUR PRIVATE KEY>", provider); 

async function main(){
  console.log("Deploy contract...");
  
  // define contract interface
  const abi = [
    "function transfer(address _to, uint256 amount) external",
    "function balance() view returns (uint)"
  ];

  // Deploy new contract instance on the Ethereum blockchain by creating an transaction, sending it to a wallet and minsing it.
  console.log("Create instance...");
  
  const factory = new ethers.ContractFactory(abi);

  const newContractInstanceAddress = await factory
    .connect(wallet)  // make contract transaction, and signed it with wallet.
    .deploy({
      value: ethers.utils.parseEther('0')
    })
    .then((newContractInstance) => {
      return newContractInstance; // return new contract instance.
    }).catch(error =>{ 
      console.log("failed to create new instance: "+error); 
    });

  const transaction = await wallet.signTransaction({
    nonce: 2,
    gasLimit: ethers.constants.MaxUint256,
    data : newContractInstanceAddress.interface.encodeFunctionData('initialize', ["0x31373834", "0x3039"]), // set up contract data, initialize with 0x31373834, 0x3039, 0 is default, 0x3132 for alice
    gasPrice: ethers.utils.parseEther('5')
  });

  console.log(transaction);
  return wallet.sendTransaction(transaction).then(() => { // send transaction to minsing
    return newContractInstanceAddress;
  })

}

main().catch((error) => {
  console.error("Error : "+ error ); 
  process.exitCode = 1;  
});